import Vue from 'vue';
import VueRouter from 'vue-router';
import BusinessSecurity from '@/pages/BusinessSecurity/Index.vue';
Vue.use(VueRouter);

// const BusinessSecurity = () => import('@/pages/BusinessSecurity/Index.vue');

const routes = [
  { path: '/BusinessSecurity', component: BusinessSecurity },
  {
    path: '*',
    redirect: '/BusinessSecurity',
  },
];

// 使用 history 模式保持 spa url 的美观性
const router = new VueRouter({
  // mode: 'history',
  base: process.env.BASE_URL,
  routes,
});

export default router;
