<template>
  <SquareWrap>
    <div class="attack-box">
      <TitleBar :titleName="BusinesData.ipAttackListTitle" :imgSrc="3"></TitleBar>
      <div class="sub-title">
        <div>时间</div>
        <div>姓名</div>
        <div>地点</div>
        <div>类型</div>
      </div>
      <div class="swiper-container swiper-no-swiping" ref="swiperContainer">
        <div class="swiper-wrapper">
          <div class="swiper-slide swiper-item" v-for="(item, i) in infoList" :key="i">
            <div>
              <div class="time">{{ item.time }}</div>
              <div class="ip">{{ item.ip }}</div>
              <div class="api">{{ item.cgi }}</div>
              <div class="type">{{ item.level }}</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </SquareWrap>
</template>

<script>
import SquareWrap from '@/components/SquareWrap.vue';
import TitleBar from '../BlockTitleBar';
import Swiper from 'swiper';
import moment from 'moment';
import { mapState } from 'vuex';

export default {
  components: {
    SquareWrap,
    TitleBar,
  },
  data() {
    return {
      infoList: [],
    };
  },
  computed: {
    ...mapState(['BusinesData']),
  },

  mounted() {
    this.initSwiper(this.BusinesData.ipAttackList);
  },
  methods: {
    initSwiper(swiperData) {
      const that = this;
      const maxLimit = 200; // 允许最大数据量，过大会导致swiper卡顿
      const minLimit = 50;
      const date = new Date().getTime() - 1200 * 7;
      let tempList = swiperData.length > maxLimit ? swiperData.slice(0, maxLimit) : swiperData;
      while (tempList.length < minLimit) {
        tempList = tempList.concat(JSON.parse(JSON.stringify(tempList)));
      }
      const len = tempList.length;
      const split = Math.floor(len / 4);
      this.infoList = tempList.map((item, i) => {
        item.time = moment(date + 1200 * i).format('YYYY-MM-DD H:mm:ss');
        return item;
      });

      this.$nextTick(() => {
        new Swiper(this.$refs.swiperContainer, {
          direction: 'vertical',
          slidesPerView: 7,
          height: 240,
          speed: 1200,
          initialSlide: 0,

          freeMode: true,
          observer: true,
          observeParents: true,
          roundLengths: true,
          loopPreventsSlide: false,

          autoplay: {
            delay: 0,
            disableOnInteraction: false,
          },
          on: {
            slideChangeTransitionEnd() {
              if (that.infoList.length > maxLimit) {
                this.slideTo(0, 0, false);
                const date = new Date().getTime() - 1200 * 7;
                that.infoList = tempList.slice(0, len).map((item, i) => {
                  item.time = moment(date + 1200 * i).format('YYYY-MM-DD H:mm:ss');
                  return item;
                });
                return;
              }
              if (
                this.activeIndex % split === 0 &&
                that.infoList.length - this.activeIndex <= split
              ) {
                const date = new Date().getTime();
                const temp = that.infoList
                  .slice(this.activeIndex % len, (this.activeIndex % len) + split)
                  .map((item, i) => {
                    item.time = moment(date + i * 1200).format('YYYY-MM-DD H:mm:ss');
                    return item;
                  });
                that.infoList.push(...temp);
              }
            },
          },
        });
      });
    },
  },
};
</script>

