/* eslint-disable */
import * as THREE from 'three';

// 地图数据解码
export const decode = (json) => {
  if (!json.UTF8Encoding) {
    return json;
  }
  let encodeScale = json.UTF8Scale;
  if (!encodeScale) {
    encodeScale = 1024;
  }
  const features = json.features;

  features.forEach((feature) => {
    const geometry = feature.geometry;
    const coordinates = geometry.coordinates;
    const encodeOffsets = geometry.encodeOffsets;
    coordinates.forEach((coordinate, c) => {
      if (geometry.type === 'Polygon') {
        coordinates[c] = decodePolygon(coordinate, encodeOffsets[c], encodeScale);
      } else if (geometry.type === 'MultiPolygon') {
        coordinate.forEach((polygon, c2) => {
          coordinate[c2] = decodePolygon(polygon, encodeOffsets[c][c2], encodeScale);
        });
      }
    });
  });
  // Has been decoded
  json.UTF8Encoding = false;
  return json;
};

// 创建 三维二次贝塞尔曲线
export const createBezierCurve3 = (p1, p2) => {
  // distance
  const d = p1.distanceTo(p2);
  const mid = new THREE.Vector3(
    (p1.x + p2.x) / 2 + (Math.random() * d) / 4 - d / 8,
    (p1.y + p2.y) / 2 + (Math.random() * d) / 4 - d / 8,
    (p1.z + p2.z) / 2 + (Math.random() * d) / 4 + d / 8 + 2
  );
  return new THREE.QuadraticBezierCurve3(p1, mid, p2);
};

/**
 * @desc 解码
 */
export const decodePolygon = (coordinate, encodeOffsets, encodeScale) => {
  const result = [];
  let prevX = encodeOffsets[0];
  let prevY = encodeOffsets[1];

  for (let i = 0; i < coordinate.length; i += 2) {
    let x = coordinate.charCodeAt(i) - 64;
    let y = coordinate.charCodeAt(i + 1) - 64;
    // ZigZag decoding
    x = (x >> 1) ^ -(x & 1);
    y = (y >> 1) ^ -(y & 1);
    // Delta deocding
    x += prevX;
    y += prevY;

    prevX = x;
    prevY = y;
    // Dequantize
    result.push([x / encodeScale, y / encodeScale]);
  }
  return result;
};
