<template>
  <SquareWrap :height="510" :width="670">
    <div class="attack-box">
      <TitleBar titleName="疫情排行" :imgSrc="6"></TitleBar>
      <div class="sub-title">
        <div>{{ BusinesData.domesticTopTitle }}</div>
        <div>{{ BusinesData.ipTopTitle }}</div>
      </div>
      <div class="rank-box">
        <div class="region-box">
          <div class="sort-item" v-for="(item, i) in BusinesData.domesticTop" :key="i">
            <div class="sort">{{ i + 1 }}</div>
            <div class="place">{{ item.name }}</div>
            <div class="renge">
              <span
                v-for="(citem, i) in getGradientColors(getPercent(item.value))"
                :key="i"
                :style="{ backgroundColor: citem }"
                class="progress-item"
              ></span>
            </div>
            <div class="num">{{ item.value }}</div>
          </div>
        </div>
        <div class="bus-box">
          <div class="sort-item" v-for="(item, i) in BusinesData.ipTop" :key="i">
            <div class="sort">{{ i + 1 }}</div>
            <div class="place">{{ item.name }}</div>
            <div class="num">{{ item.value }}</div>
          </div>
        </div>
      </div>
    </div>
  </SquareWrap>
</template>

<script>
import SquareWrap from '@/components/SquareWrap.vue';
import TitleBar from '../BlockTitleBar';
import { gradientColors } from '@/common/utils';
import { mapState } from 'vuex';
export default {
  components: {
    SquareWrap,
    TitleBar,
  },
  computed: {
    ...mapState(['BusinesData']),
  },
  mounted() {},
  filters: {
    round(value) {
      return `${(value / 100000000).toFixed(2)}亿`;
    },
  },
  methods: {
    getPercent(num) {
      const sum = this.BusinesData.domesticTop.reduce((sum, item) => {
        return (sum += Number(item.value));
      }, 0);
      return (num / sum).toFixed(2);
    },
    // 100%  == 30  -  1
    getGradientColors(percentage) {
      const nums = Math.ceil(percentage * 30);
      return gradientColors('#70E9FC', '#FBE19A', nums);
    },
  },
};
</script>

