<template>
  <SquareWrap>
    <div class="attack-box">
      <TitleBar :titleName="BusinesData.requestTrendTitle" :imgSrc="2"></TitleBar>
      <div class="chart-box" ref="chart-dom"></div>
    </div>
  </SquareWrap>
</template>

<script>
import SquareWrap from '@/components/SquareWrap.vue';
import TitleBar from '../BlockTitleBar';
import { mapState } from 'vuex';
import moment from 'moment';
export default {
  components: {
    SquareWrap,
    TitleBar,
  },
  mounted() {
    const chart = this.$echarts.init(this.$refs['chart-dom']);
    const option = this.setOption();
    chart.setOption(option);
  },
  computed: {
    ...mapState(['BusinesData']),
  },

  methods: {
    getData() {
      return this.BusinesData.requestTrend;
    },
    setOption() {
      const Data = this.getData();
      const dataAxis = Data.date
        .map((item, i) => {
          return moment().subtract(i, 'days').format('yyyy-MM-DD');
        })
        .reverse();

      const data1 = Data.list[0].data.map((item) => {
        return item;
      });

      const data2 = Data.list[1].data.map((item) => item * 100);

      return {
        legend: {
          data: [
            {
              name: '已打卡',
            },
            {
              name: '未打卡',
            },
          ],
          itemWidth: 18,
          itemHeight: 18,
          itemGap: 20,
          icon: 'rect',
          textStyle: {
            color: '#bfbfc1',
            fontSize: 17,
            lineHeight: 24,
          },
        },
        grid: {
          top: 60,
          left: 20,
          right: 10,
          bottom: 20,
          containLabel: true,
        },
        xAxis: {
          data: dataAxis,
          splitLine: {
            show: false,
          },
          axisLabel: {
            margin: 20,
            inside: false,
            textStyle: {
              color: '#c7c7c8',
              fontSize: 16,
            },
          },
          axisLine: {
            show: true,
            lineStyle: {
              color: '#236AF6',
              width: 5,
            },
          },
        },
        yAxis: [
          {
            type: 'value',
            name: '已打卡',
            axisLine: {
              show: true,
              lineStyle: {
                color: '#236AF6',
                width: 5,
              },
            },

            axisTick: {
              show: false,
            },
            splitLine: {
              show: true,
              lineStyle: {
                color: '#F2F2F2',
                width: 1,
              },
            },
            axisLabel: {
              formatter: `{value} `,
              textStyle: {
                color: '#60DBFB',
                fontSize: 16,
              },
            },
          },
          {
            type: 'value',
            name: '未打卡',
            min: 0,
            axisLine: {
              show: true,
              lineStyle: {
                color: '#236AF6',
                width: 5,
              },
            },
            axisTick: {
              show: false,
            },
            splitLine: {
              show: true,
              lineStyle: {
                color: '#F2F2F2',
                width: 1,
              },
            },
            axisLabel: {
              formatter: `{value} %`,
              textStyle: {
                color: '#60DBFB',
                fontSize: 16,
              },
            },
          },
        ],
        series: [
          {
            name: '已打卡',
            type: 'bar',
            itemStyle: {
              color: new this.$echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 1, color: '#002BBB' },
                { offset: 0, color: '#51BEF4' },
              ]),
            },
            barWidth: 30,
            emphasis: {
              itemStyle: {
                color: new this.$echarts.graphic.LinearGradient(0, 0, 0, 1, [
                  { offset: 0, color: '#002BBB' },
                  { offset: 1, color: '#51BEF4' },
                ]),
              },
            },
            data: data1,
          },
          {
            name: '未打卡',
            type: 'line',
            yAxisIndex: 1,
            itemStyle: {
              color: new this.$echarts.graphic.LinearGradient(0, 0, 0, 1, [
                { offset: 0, color: '#FFAB96' },
                { offset: 1, color: '#FF0F47' },
              ]),
            },
            data: data2,
          },
        ],
      };
    },
  },
};
</script>

<style lang="less" scoped>
.attack-box {
  box-sizing: border-box;
  padding: 45px 70px;
  .chart-box {
    height: 280px;
    margin: 0 auto;
    margin-left: -20px;
    margin-right: -20px;
  }
}
</style>
