<template>
  <div class="part-box">
    <LightBox :width="340" :height="370" class="region-box">
      <TitleBar titleName="流量总览"></TitleBar>
      <div class="ip-count-box">
        总流量(出/入)：{{ (BSDataModel.overView.ipV4 + BSDataModel.overView.ipV6).toFixed(2) }}PB
      </div>
      <div class="ip-box">
        <div class="text-box">
          <span>IPv4流量:</span>{{ BSDataModel.overView.ipV4.toFixed(2) }}PB {{ v4percent }}%
        </div>
        <div class="progress">
          <div class="bg"></div>
          <div class="content" :style="{ width: `${v4percent}%` }"></div>
        </div>
      </div>
      <div class="ip-box">
        <div class="text-box">
          <span>IPv6流量:</span>{{ BSDataModel.overView.ipV6.toFixed(2) }}PB
          {{ (100 - v4percent).toFixed(2) }}%
        </div>
        <div class="progress">
          <div class="bg"></div>
          <div class="content" :style="{ width: `${100 - v4percent}%` }"></div>
        </div>
      </div>
    </LightBox>
  </div>
</template>

<script>
import { mapState } from 'vuex';
import TitleBar from './TitleBar';
import LightBox from './LightBox';
export default {
  components: {
    LightBox,
    TitleBar,
  },
  computed: {
    ...mapState(['BSDataModel']),
    v4percent() {
      const percent =
        (this.BSDataModel.overView.ipV4 /
          (this.BSDataModel.overView.ipV4 + this.BSDataModel.overView.ipV6)) *
        100;
      return Number(percent.toString().match(/^\d+(?:\.\d{0,2})?/)[0]).toFixed(2);
    },
  },
};
</script>

