<script>
import { mapState } from 'vuex';
export default {
  computed: {
    ...mapState(['BSDataModel']),
    v4percent() {
      const percent =
        (this.BSDataModel.AIBlock.UnusualIPv4 /
          (this.BSDataModel.AIBlock.UnusualIPv4 + this.BSDataModel.AIBlock.UnusualIPv6)) *
        100;
      return Number(percent.toFixed(3));
      // return Number(percent.toString().match(/^\d+(?:\.\d{0,2})?/)[0]).toFixed(3);
    },
  },
  data() {
    return {
      sum: 23221,
      timer: null,
      num: 0,
    };
  },
  mounted() {
    this.timer = setInterval(() => {
      const oTime = new Date(new Date().toLocaleDateString()).getTime();
      const nTime = new Date().getTime();
      const percent = (((nTime - oTime) / (1000 * 60 * 60 * 24)) * 100) / 100;
      this.num = Math.floor(this.sum * percent);
      console.log(233);
    }, 1000);
  },
  destroyed() {
    clearInterval(this.timer);
  },
};
