import * as THREE from 'three';
import * as d3 from 'd3-geo';
import Stats from 'three/examples/jsm/libs/stats.module.js';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
import { decode, createBezierCurve3 } from './util.js';

import { Line2 } from 'three/examples/jsm/lines/Line2.js';
import { LineMaterial } from 'three/examples/jsm/lines/LineMaterial.js';
import { LineGeometry } from 'three/examples/jsm/lines/LineGeometry.js';
import { Flow } from 'three/examples/jsm/modifiers/CurveModifier.js';
import { EffectComposer } from 'three/examples/jsm/postprocessing/EffectComposer.js';
import { UnrealBloomPass } from 'three/examples/jsm/postprocessing/UnrealBloomPass.js';
import { RenderPass } from 'three/examples/jsm/postprocessing/RenderPass.js';
import { ShaderPass } from 'three/examples/jsm/postprocessing/ShaderPass.js';
import { FXAAShader } from 'three/examples/jsm/shaders/FXAAShader.js';
import TWEEN from '@tweenjs/tween.js';

import chinaOutLine from './chinaOutLine.json';
import chinaMapData from './chinaMap.json';
import attackInfo from './attackInfo';
import dotInverted from './assets/dot-inverted.png';
import ringExplosion from './assets/ring_explosion.jpg';

class Map {
  constructor(option) {
    this.opt = option;
    this.sceneDomElement = option.element;
    this.attackInfo = attackInfo;
    this.mapData = chinaMapData;
    this.outLineData = chinaOutLine;
    this.scene = null;
    this.camera = null;
    this.renderer = null;
    this.animationId = null;
    this.stop = false;
    this.bloomComposer = null;
    this.finalComposer = null;
    this.ENTIRE_SCENE = 0;
    this.BLOOM_SCENE = 1;
    this.bloomLayer = new THREE.Layers();
    this.bloomLayer.set(this.BLOOM_SCENE);
    this.darkMaterial = new THREE.MeshBasicMaterial({
      color: 'black',
      opacity: 0,
    });
    this.materials = {};

    this.flows = [];
    this.tweenGroup = [];
    this.group = new THREE.Group(); // 地图模块

    this.init();
  }
  init() {
    this.initScene();
    this.initCamera();
    this.initRender();
    // this.initStats();
    this.initLight();
    this.initOrbitControls();
    this.initComposer();
    this.winReSize();

    this.main();
    this.render();
  }
  initComposer() {
    const params = {
      exposure: 0,
      bloomStrength: 1.9,
      bloomThreshold: 0,
      bloomRadius: 0.5,
    };

    const effectFXAA = new ShaderPass(FXAAShader);
    effectFXAA.uniforms.resolution.value.set(0.6 / window.innerWidth, 0.6 / window.innerHeight);
    effectFXAA.renderToScreen = true;
    const renderScene = new RenderPass(this.scene, this.camera);
    const bloomPass = new UnrealBloomPass(
      new THREE.Vector2(window.innerWidth, window.innerHeight),
      1.5,
      0.4,
      0.85
    );
    bloomPass.threshold = params.bloomThreshold;
    bloomPass.strength = params.bloomStrength;
    bloomPass.radius = params.bloomRadius;

    const bloomComposer = new EffectComposer(this.renderer);
    bloomComposer.renderToScreen = false;
    bloomComposer.addPass(renderScene);
    bloomComposer.addPass(bloomPass);
    bloomComposer.addPass(effectFXAA);
    this.bloomComposer = bloomComposer;

    const finalPass = new ShaderPass(
      new THREE.ShaderMaterial({
        uniforms: {
          baseTexture: { value: null },
          bloomTexture: { value: bloomComposer.renderTarget2.texture },
        },
        vertexShader: `varying vec2 vUv;void main() {vUv = uv;gl_Position = projectionMatrix * modelViewMatrix * vec4( position, 1.0 );}`,
        fragmentShader: `uniform sampler2D baseTexture;uniform sampler2D bloomTexture;varying vec2 vUv;void main() {gl_FragColor = ( texture2D( baseTexture, vUv ) + vec4( 1.0 ) * texture2D( bloomTexture, vUv ) );}`,
        defines: {},
      }),
      'baseTexture'
    );
    finalPass.needsSwap = true;

    const finalComposer = new EffectComposer(this.renderer);
    finalComposer.addPass(renderScene);
    finalComposer.addPass(finalPass);
    finalComposer.addPass(effectFXAA);
    this.finalComposer = finalComposer;
  }
  main() {
    this.drawChinaOutLine();
    this.drawMap();
    this.drawAttackPoints();
    this.drawAttackLines();
    this.drwaExplosion();

    this.scene.add(this.group);
    // this.group.position.y = 0.2;
    this.group.rotateX(-Math.PI * 0.5);
    this.group.rotateZ(-Math.PI * 0.5);

    this.group.scale.set(1.15, 1.15, 1.15);
    this.tweenGroup.push(
      new TWEEN.Tween(this.group)
        .to({ rotation: { x: -Math.PI * 0.7 }, scale: { x: 1.03, y: 1.03, z: 1.03 } }, 15000)
        .yoyo(true)
        .repeat(Infinity)
        .start()
    );
  }
  drawChinaOutLine() {
    const outLineGroup = new THREE.Group();
    outLineGroup.name = 'outLineGroup';
    const MapGeoV3 = this.geoToPosV3(this.outLineData);
    MapGeoV3.features.forEach((d) => {
      const g = new THREE.Group();
      g.data = d;
      d.vector3.forEach((points) => {
        // 多个面
        if (points[0][0] instanceof Array) {
          points.forEach((p) => {
            const mesh = this.drawModel(p);
            const topLineMesh = this.drawLine(p, 6);
            topLineMesh.layers.enable(this.BLOOM_SCENE);
            topLineMesh.renderOrder = 99;
            g.add(topLineMesh);
            g.add(mesh);
          });
        } else {
          // 单个面
          const mesh = this.drawModel(points);
          const topLineMesh = this.drawLine(points, 6);
          topLineMesh.layers.enable(this.BLOOM_SCENE);
          topLineMesh.position.z = 2;
          g.add(topLineMesh);
          g.add(mesh);
        }
      });
      outLineGroup.add(g);
    });
    this.group.add(outLineGroup);
  }
  drwaExplosion() {
    const geometry = new THREE.CircleGeometry(3, 20);
    const texture = new THREE.TextureLoader().load(ringExplosion);
    const material = new THREE.MeshLambertMaterial({
      transparent: true,
      emissive: 0x4aabf8,
      side: THREE.DoubleSide,
      depthWrite: false,
      flatShading: true,
      alphaMap: texture,
      opacity: 0.5,
    });
    const mesh = new THREE.Mesh(geometry, material);
    mesh.layers.enable(this.BLOOM_SCENE);
    mesh.position.set(-15, 0, -2);
    mesh.renderOrder = 97;
    this.tweenGroup.push(
      new TWEEN.Tween(mesh)
        .to({ scale: { x: 17, y: 17 }, material: { opacity: 0 } }, 1500)
        .repeatDelay(3500)
        .repeat(Infinity)
        .easing(TWEEN.Easing.Cubic.Out)
        .start()
    );
    this.group.add(mesh);
  }
  drawAttackPoints() {
    const group = new THREE.Group();
    group.name = 'pointGroup';
    const boxGeometry = new THREE.BoxGeometry(0.08, 0.08, 5);
    const boxMaterial = new THREE.MeshLambertMaterial({
      transparent: true,
      opacity: 0.9,
      emissive: new THREE.Color(0xffffff),
      emissiveIntensity: 100,
      flatShading: true,
    });
    const boxMesh = new THREE.Mesh(boxGeometry, boxMaterial);

    const places = [];
    this.attackInfo.forEach((item) => {
      if (!places.some((it) => it.name === item.origin.name)) {
        places.push(item.origin);
      }
      if (!places.some((it) => it.name === item.target.name)) {
        places.push(item.target);
      }
    });

    places.forEach((item) => {
      const v3 = new THREE.Vector3(...this.lnglatToMector(item.position));
      // 圆柱
      const mesh = boxMesh.clone();
      mesh.position.set(v3.x, v3.y, v3.z + 2.5);
      group.add(mesh);
      // sprite
      const label = this.makeLabel(item.name);
      label.position.set(v3.x, v3.y - 0.475, v3.z + 5.21);
      group.add(label);
      // wave
      const glowMesh = this.drawGlowPoint(v3);
      group.add(glowMesh);
    });

    this.group.add(group);
  }
  drawGlowPoint(posV3) {
    //   const geometry = new THREE.BoxGeometry(1, 1, 1);
    const geometry = new THREE.CircleGeometry(1, 20);
    const texture = new THREE.TextureLoader().load(dotInverted);
    const material = new THREE.MeshLambertMaterial({
      transparent: true,
      color: 0xff0000,
      emissive: 0xff0000,
      side: THREE.DoubleSide,
      depthWrite: false,
      flatShading: true,
      alphaMap: texture,
    });
    const mesh = new THREE.Mesh(geometry, material);

    mesh.position.set(posV3.x, posV3.y, posV3.z + 0.2);
    const animation = new TWEEN.Tween(mesh)
      .to({ scale: { x: 4, y: 4, z: 4 }, material: { opacity: 0 } }, Math.random() * 1000 + 1000)
      .repeatDelay(400)
      .repeat(Infinity)
      .start();
    this.tweenGroup.push(animation);
    mesh.layers.enable(this.BLOOM_SCENE);
    return mesh;
  }
  makeLabel(name) {
    const canvas = this.makeLabelCanvas(name);
    const texture = new THREE.CanvasTexture(canvas);
    const labelMaterial = new THREE.SpriteMaterial({
      map: texture,
      transparent: true,
    });
    const label = new THREE.Sprite(labelMaterial);
    // const width = labelMaterial.map.image.width;
    // const height = labelMaterial.map.image.height;
    // label.center.x = 0;
    // label.center.y = 0;
    label.scale.set(5, 2.5, 1);
    return label;
  }
  makeLabelCanvas(name) {
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    const h = 90;
    const w = 180;
    const fontSize = 40;
    context.strokeStyle = '#0864ee';
    context.strokeRect(0, 0, w, h);
    context.fillStyle = 'rgba(10,18,51,0.3)';
    context.fillRect(1, 1, w, h);
    /* 字体颜色 */
    context.fillStyle = 'rgba(220,220,220,0.55)';
    context.font = `${fontSize}px bolder`;
    /* 文字 */
    context.textAlign = 'center';
    context.fillText(name, w / 2, h / 2 + fontSize / 2 - 5);

    return context.canvas;
  }
  drawAttackLines() {
    const flowsGroup = new THREE.Group();
    flowsGroup.name = 'flowsGroup';

    this.attackInfo.forEach((item) => {
      const originPos = this.lnglatToMector(item.origin.position);
      const targetPos = this.lnglatToMector(item.target.position);

      const originV3 = new THREE.Vector3(...originPos);
      const targetV3 = new THREE.Vector3(...targetPos);

      const lineGroup = new THREE.Group();
      lineGroup.name = `${item.origin.name}to${item.target.name}`;

      new Array(item.num).fill(0).forEach(() => {
        const curve = createBezierCurve3(originV3, targetV3);
        lineGroup.add(this.createCurveMesh(curve, item));
        lineGroup.add(this.addMovingBox(curve));
      });
      lineGroup.position.z = -0.01;
      flowsGroup.add(lineGroup);
    });
    this.group.add(flowsGroup);
  }
  createCurveMesh(curve, item) {
    const points = curve.getPoints(50).reduce((arr, item) => {
      return arr.concat(item.x, item.y, item.z);
    }, []);
    const geometry = new LineGeometry();
    geometry.setPositions(points);
    const material = new LineMaterial({
      color: item.color ? new THREE.Color(item.color) : 0xff0000,
      linewidth: 0.5,
    });
    material.resolution.set(this.sceneDomElement.clientWidth, this.sceneDomElement.clientHeight);
    const line = new Line2(geometry, material);
    line.computeLineDistances();
    return line;
  }
  addMovingBox(curve) {
    const path = new THREE.Path();
    path.lineTo(1, 10);
    path.arc(-1, 0, 1, 0, Math.PI / 2);
    const points = path.getPoints(30);

    const boxGeometry = new THREE.LatheGeometry(points, 10, 0, Math.PI * 2);
    boxGeometry.scale(0.04, 0.04, 0.04);

    const normalBoxMaterial = new THREE.MeshLambertMaterial({
      transparent: true,
      opacity: 0.6,
      emissive: new THREE.Color(0xffffff),
      flatShading: true,
      emissiveIntensity: 1,
    });
    const attackBoxMaterial = new THREE.MeshLambertMaterial({
      transparent: true,
      opacity: 0.6,
      color: new THREE.Color(0xe60e40),
      emissive: new THREE.Color(0xe60e40),
      flatShading: true,
      emissiveIntensity: 1,
    });
    const normalMesh = new THREE.Mesh(boxGeometry, normalBoxMaterial);
    const attackMesh = new THREE.Mesh(boxGeometry, attackBoxMaterial);

    const objs = new THREE.Group();
    for (let i = 0; i < 4; i++) {
      const flow = new Flow(Math.random() > 0.8 ? attackMesh : normalMesh);

      flow.updateCurve(0, curve);

      this.flows.push(flow);
      flow.uniforms.flow.value = -1;
      flow.speed = Math.random() * 0.005 + 0.005;
      flow.object3D.name = 'flowObj';
      flow.object3D.geometry.center();
      flow.object3D.layers.enable(this.BLOOM_SCENE);
      objs.add(flow.object3D);
    }
    return objs;
  }
  drawMap() {
    this.drawMapModel();
  }
  // 绘制地图
  drawMapModel() {
    const modelGroup = new THREE.Group();
    modelGroup.name = 'mapGroup';
    const MapGeoV3 = this.geoToPosV3(this.mapData);
    MapGeoV3.features.forEach((d) => {
      const g = new THREE.Group();
      g.data = d;
      d.vector3.forEach((points) => {
        // 多个面
        if (points[0][0] instanceof Array) {
          points.forEach((p) => {
            // const mesh = this.drawModel(p);
            const topLineMesh = this.drawLine(p);
            // const bottomLineMesh = topLineMesh.clone();
            // bottomLineMesh.position.z = -3;
            g.add(topLineMesh);
            // g.add(bottomLineMesh);
            // g.add(mesh);
          });
        } else {
          // 单个面
          // const mesh = this.drawModel(points);
          const topLineMesh = this.drawLine(points);
          // const bottomLineMesh = topLineMesh.clone();
          // bottomLineMesh.position.z = -3;
          g.add(topLineMesh);
          // g.add(bottomLineMesh);
          // g.add(mesh);
        }
      });
      modelGroup.add(g);
    });
    this.group.add(modelGroup);
  }
  // 绘制地图模型
  drawModel(points) {
    const shape = new THREE.Shape();
    points.forEach((d, i) => {
      const [x, y] = d;
      if (i === 0) {
        shape.moveTo(x, y);
      } else if (i === points.length - 1) {
        shape.quadraticCurveTo(x, y, x, y);
      } else {
        shape.lineTo(x, y, x, y);
      }
    });
    const geometry = new THREE.ExtrudeGeometry(shape, {
      steps: 4,
      curveSegments: 20,
      depth: -3,
      bevelEnabled: false,
      bevelThickness: 1,
      bevelSize: 1,
      bevelSegments: 1,
    });
    const material = new THREE.MeshLambertMaterial({
      color: 0x2f3f8f,
      transparent: true,
      opacity: 0.3,
      side: THREE.DoubleSide,
    });
    const mesh = new THREE.Mesh(geometry, material);
    mesh.layers.enable(this.BLOOM_SCENE);
    return mesh;
  }
  // 绘制线
  drawLine(points, linewidth = 3) {
    const material = new LineMaterial({
      color: 0x194aba,
      linewidth,
      transparent: true,
      opacity: 1,
      side: THREE.FrontSide,
      depthWrite: false,
      flatShading: true,
      transparent: false,
    });
    const geometry = new LineGeometry();
    const positions = [];
    points.forEach((d) => {
      const [x, y, z] = d;
      positions.push(x, y, z);
    });
    material.resolution.set(this.sceneDomElement.clientWidth, this.sceneDomElement.clientHeight);
    geometry.setPositions(positions);
    const line = new Line2(geometry, material);
    line.computeLineDistances();
    line.layers.enable(this.BLOOM_SCENE);
    line.renderOrder = 98;
    return line;
  }
  geoToPosV3(geoJson) {
    const decodeMapData = decode(geoJson);
    decodeMapData.features.forEach((d) => {
      d.vector3 = [];
      d.geometry.coordinates.forEach((coordinates, i) => {
        d.vector3[i] = [];
        coordinates.forEach((c, j) => {
          if (c[0] instanceof Array) {
            d.vector3[i][j] = [];
            c.forEach((cinner) => {
              const cp = this.lnglatToMector(cinner);
              d.vector3[i][j].push(cp);
            });
          } else {
            const cp = this.lnglatToMector(c);
            d.vector3[i].push(cp);
          }
        });
      });
    });
    return decodeMapData;
  }

  /**
   * @desc 经纬度转换成墨卡托投影
   * @param {array} 传入经纬度
   * @return array [x,y,z]
   */
  lnglatToMector(lnglat) {
    if (!this.projection) {
      this.projection = d3.geoMercator().center([104, 32]).scale(80).translate([0, 0]);
    }
    const [y, x] = this.projection([...lnglat]);
    const z = 0;
    return [x, y, z];
  }
  animation() {
    // console.log('map render');
    // console.log(this.animationId);
    this.flows.forEach((item) => {
      item.moveAlongCurve(item.speed);
    });
    this.tweenGroup.forEach((item) => {
      item.update();
    });
  }

  composerRendering() {
    this.scene.traverse((obj) => {
      if (obj.isMesh && this.bloomLayer.test(obj.layers) === false) {
        this.materials[obj.uuid] = obj.material;
        obj.material = this.darkMaterial;
      }
    });
    this.bloomComposer.render();
    this.scene.traverse((obj) => {
      if (this.materials[obj.uuid]) {
        obj.material = this.materials[obj.uuid];
        delete this.materials[obj.uuid];
      }
    });
    this.finalComposer.render();
  }
  rendering() {
    // this.stats.update();
    this.composerRendering();
    // this.renderer.render(this.scene, this.camera);
  }
  render() {
    this.animation(); // 动画
    this.rendering(); // 渲染

    if (!this.stop) this.animationId = requestAnimationFrame(this.render.bind(this));
  }
  initScene() {
    this.scene = new THREE.Scene();
  }
  initCamera() {
    this.camera = new THREE.PerspectiveCamera(
      70,
      this.sceneDomElement.clientWidth / this.sceneDomElement.clientHeight,
      1,
      100000
    );

    // this.camera.position.set(0, 38, 22);
    this.camera.position.set(0, 58, 30);
  }
  initRender() {
    this.renderer = new THREE.WebGLRenderer({
      antialias: true, // 抗锯齿
      // logarithmicDepthBuffer: true,
      alpha: true,
    });
    this.renderer.setPixelRatio(window.devicePixelRatio); // 设置分辨率
    this.renderer.setSize(this.sceneDomElement.clientWidth, this.sceneDomElement.clientHeight);
    this.sceneDomElement.appendChild(this.renderer.domElement);
  }
  initStats() {
    this.stats = new Stats();
    this.stats.domElement.style.position = 'absolute';
    this.stats.domElement.style.left = '0px';
    this.stats.domElement.style.top = '0px';
    document.body.appendChild(this.stats.domElement);
  }
  initOrbitControls() {
    this.controls = new OrbitControls(this.camera, this.renderer.domElement);
  }
  initLight() {
    this.scene.add(new THREE.AmbientLight(0xccccff, 0.08));
    const directionalLightFront = new THREE.DirectionalLight(0xccccff, 0.4);
    directionalLightFront.position.set(0, 0, 200);
    this.scene.add(directionalLightFront);

    // this.scene.add(new THREE.AxesHelper(50));
  }
  winReSize() {
    window.onresize = () => {
      this.renderer.setSize(this.sceneDomElement.clientWidth, this.sceneDomElement.clientHeight);
      this.camera.aspect = this.sceneDomElement.clientWidth / this.sceneDomElement.clientHeight;
      this.camera.updateProjectionMatrix();
    };
  }
  beginRendering() {
    this.stop = false;
    this.render();
    this.renderer.setSize(this.sceneDomElement.clientWidth, this.sceneDomElement.clientHeight);
    this.camera.aspect = this.sceneDomElement.clientWidth / this.sceneDomElement.clientHeight;
    this.camera.updateProjectionMatrix();
  }
  stopRendering() {
    while (this.animationId) {
      cancelAnimationFrame(this.animationId);
      this.animationId = null;
    }
    this.stop = true;
  }
  removeScene() {
    cancelAnimationFrame(this.animationId);
    this.scene.traverse((child) => {
      if (child.material) {
        child.material.dispose();
      }
      if (child.geometry) {
        child.geometry.dispose();
      }
      child = null;
    });

    this.renderer.forceContextLoss();
    this.renderer.dispose();
    this.renderer.domElement = null;
    this.renderer = null;
    this.scene = null;
    this.camera = null;
    this.controls = null;
    this.sceneDomElement = null;
  }
}
export default Map;
