<template>
  <div class="dashboard-wrap">
    <div class="dashboard-box">
      <img
        :style="{ transform: `rotateZ(${rotateDeg}deg)` }"
        src="@/assets/images/Bussiness/rightFlow/pointer.png"
        alt=""
      />
    </div>
    <div class="text-cont">
      <div>
        <!-- <img src="@/assets/images/Bussiness/rightFlow/jt.png" alt="" /> -->
        <!-- <img src="@/assets/images/Bussiness/rightFlow/jt.png" alt="" /> -->
      </div>
      <p style=""></p>
      <span>{{ this.BusinesData.securityIndex.number }} &nbsp;&nbsp;&nbsp;</span>
    </div>
  </div>
</template>

<script>
import { mapState, mapMutations } from 'vuex';
export default {
  computed: {
    ...mapState(['BusinesData']),
    rotateDeg() {
      return (260 * this.BusinesData.securityIndex.number) / 100 - 40;
    },
  },
  methods: {
    ...mapMutations(['changeSecurityIndex']),
  },
  mounted() {
    this.timer = setInterval(() => {
      const number = 2 + Math.random() * 10;
      this.changeSecurityIndex(number.toFixed(2));
    }, 5000);
  },
  destroyed() {
    clearInterval(this.timer);
  },
};
</script>
