export default {
  nameHide: (val) => {
    const len = val.length;
    const temp = val.split('');
    if (len === 2) {
      return `${temp[0]}*`;
    }
    if (len > 2) {
      const i = Math.ceil(len / 3);
      temp.splice(i, i, ...new Array(i).fill('*'));
      return temp.join('');
    }
  },
  ipHide: (val) => {
    const temp = val.split('.');
    temp[1] = '***';
    temp[2] = '***';
    return temp.join('.');
  },
  phoneNumHide: (val) => {
    // const temp = `${val}`;
    // return temp.replace(temp.substring(3, 8), '*****');
    const temp = val.split('');
    temp.splice(3, 5, ['*****']);
    return temp.join('');
  },
  numSplit: (val) => {
    return Number(val).toLocaleString();
  },
};
