<template>
  <div class="map-component-wrap" ref="mapWrap"></div>
</template>

<script>
import Map from '@/common/Map/Map.js';
let map = null;
export default {
  name: 'mapCom',
  data() {
    return {
      map: null,
    };
  },
  watch: {
    $route() {
      console.log(map, this.$route);
      if (!map) return;
      if (this.$route.path !== '/BusinessSecurity') {
        map.stopRendering();
      } else {
        map.beginRendering();
      }
    },
  },
  mounted() {
    map = new Map({
      element: this.$refs.mapWrap,
    });
    console.log('地图初始化', map);
  },
  destroyed() {
    // map.removeScene();
  },
};
</script>

