<template>
  <SquareWrap>
    <div class="attack-box">
      <TitleBar
        class="title"
        :titleName="BusinesData.maliciousDistributionTitle"
        :imgSrc="1"
      ></TitleBar>
      <div class="chart-box" ref="chart-dom"></div>
    </div>
  </SquareWrap>
</template>

<script>
import SquareWrap from '@/components/SquareWrap.vue';
import TitleBar from '../BlockTitleBar';
import { mapState } from 'vuex';
export default {
  components: {
    SquareWrap,
    TitleBar,
  },
  computed: {
    ...mapState(['BusinesData']),
  },
  mounted() {
    const chart = this.$echarts.init(this.$refs['chart-dom']);
    const option = this.setOption();
    chart.setOption(option);
  },
  methods: {
    getData() {
      return this.BusinesData.maliciousDistribution;
    },
    setOption() {
      return {
        grid: {
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
        },
        color: ['#0041ff', '#0077ff', '#00aeff', '#00ffff', '#b6ffff'],
        series: [
          {
            type: 'pie',

            radius: [60, 100],
            center: ['50%', '50%'],
            roseType: 'radius',
            label: {
              color: '#CFCFCF',
              fontSize: 17,
              formatter: '{b}  {d}%',
            },
            labelLine: {
              length: 15,
              length2: 25,
              lineStyle: {
                width: 3,
                type: 'dashed',
              },
            },
            data: this.getData(),
          },
        ],
      };
    },
  },
};
</script>

